// Dump the canonical pine-data v6 modules to JSON for the Rust codegen crate.
//
// The TS modules (FUNCTIONS/VARIABLES/CONSTANTS as object arrays; KEYWORDS and
// the category exports as Sets) are the single source of truth, generated by the
// TS pipeline from the TradingView reference. This script re-emits them verbatim
// as JSON so pine-data-codegen can `include_str!` + serde-deserialize them
// without hand-retyping ~800 symbols. Run it after the pipeline regenerates
// pine-data to keep the JSON in sync.
//
//   node --experimental-strip-types dump-pine-data.mjs
//
// (Node >= 23.6 strips types unflagged; the flag is harmless on older 22.x.)

import { writeFileSync, readFileSync, mkdirSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
// scripts/ -> pine-data-codegen -> crates -> pine-rs -> pinelsp(root) -> pine-data
const pineData = resolve(here, "../../../../pine-data");
const outDir = resolve(here, "../data");
mkdirSync(outDir, { recursive: true });

const v6 = (f) => resolve(pineData, "v6", f);

const { FUNCTIONS } = await import(v6("functions.ts"));
const { VARIABLES } = await import(v6("variables.ts"));
const { CONSTANTS } = await import(v6("constants.ts"));
const kw = await import(v6("keywords.ts"));
const behavior = JSON.parse(readFileSync(v6("function-behavior.json"), "utf8"));

// Keywords are Sets; preserve their categorization as string arrays.
const keywords = {
  all: [...kw.KEYWORDS],
  control: [...kw.CONTROL_KEYWORDS],
  declaration: [...kw.DECLARATION_KEYWORDS],
  operator: [...kw.OPERATOR_KEYWORDS],
  literal: [...kw.LITERAL_KEYWORDS],
  type: [...kw.TYPE_KEYWORDS],
};

const write = (name, data) =>
  writeFileSync(resolve(outDir, `${name}.json`), JSON.stringify(data) + "\n");

write("functions", FUNCTIONS);
write("variables", VARIABLES);
write("constants", CONSTANTS);
write("keywords", keywords);
write("function-behavior", behavior);

console.log(
  `functions=${FUNCTIONS.length} variables=${VARIABLES.length} ` +
    `constants=${CONSTANTS.length} keywords=${keywords.all.length} ` +
    `behavior=${Object.keys(behavior.functions ?? behavior).length}`,
);
